import React, { useState, useEffect } from "react";
import axios from "axios";

const CustomerDashboard = () => {
  const [job, setJob] = useState({});
  const [jobs, setJobs] = useState([]);

  const handle = (e) =>
    setJob({ ...job, [e.target.name]: e.target.value });

  const post = async () => {
    await axios.post("http://localhost:5000/api/jobs/create", job);
    load();
  };

  const load = async () => {
    const res = await axios.get("http://localhost:5000/api/jobs/all");
    setJobs(res.data);
  };

  useEffect(() => {
    load();
  }, []);

  return (
    <div>
      <h2>Customer Dashboard</h2>

      <input name="title" onChange={handle} />
      <input name="description" onChange={handle} />
      <input name="location" onChange={handle} />
      <input name="price" onChange={handle} />

      <button onClick={post}>Post Job</button>

      {jobs.map(j => (
        <div key={j._id}>
          <h4>{j.title}</h4>
          <p>{j.status}</p>
        </div>
      ))}
    </div>
  );
};

export default CustomerDashboard;
